    let schema_sql = &[
        "CREATE TABLE categories (id SERIAL PRIMARY KEY, name TEXT NOT NULL, parent_id INTEGER REFERENCES categories(id))",
    ];

    let query_sql = "-- @name GetCategoryTree\n-- @returns :many\nWITH RECURSIVE tree AS (SELECT id, name, parent_id FROM categories WHERE parent_id IS NULL UNION ALL SELECT c.id, c.name, c.parent_id FROM categories c JOIN tree t ON c.parent_id = t.id) SELECT * FROM tree";

    let catalog = scythe_core::catalog::Catalog::from_ddl(schema_sql).unwrap();
